#include <bits/stdc++.h>
using namespace std;
void enqueue(stack<int>& stack1, stack<int>& stack2, int x){
    stack1.push(x);
}
int dequeue(stack<int>& stack1, stack<int>& stack2){
    if(stack2.empty()){
        while(!stack1.empty()){
            stack2.push(stack1.top());
            stack1.pop();
        }
    }
    if(!stack2.empty()){
        int top = stack2.top();
        stack2.pop();
        return top;
    }
    return -1;
}
int main(){
    int n;
    cin >> n;
    stack<int> stack1, stack2;
    for(int i = 0; i < n; i++){
        string op;
        cin >> op;
        if(op == "push"){
            int x;
            cin >> x;
            enqueue(stack1, stack2, x);
        } else {
            cout << dequeue(stack1, stack2) << endl;
        }
    }
    return 0;
}
